import type {
  PurchaseInvoiceFieldErrors,
  PurchaseInvoiceLineFieldErrors,
  PurchaseInvoiceLineRow,
} from '../types/purchaseInvoice.types';

export function collectPurchaseInvoiceBannerMessages(fe: PurchaseInvoiceFieldErrors): string[] {
  const messages: string[] = [];
  if (fe.invoiceDate) messages.push(fe.invoiceDate);
  if (fe.supplierId) messages.push(fe.supplierId);
  if (fe.creditAccountCode) messages.push(fe.creditAccountCode);
  if (fe.vatAccountCode) messages.push(fe.vatAccountCode);
  if (fe.lines) {
    Object.keys(fe.lines)
      .map(Number)
      .sort((a, b) => a - b)
      .forEach(idx => {
        const lineErr = fe.lines?.[idx];
        if (lineErr?.materialCode) messages.push(lineErr.materialCode);
        if (lineErr?.quantity) messages.push(lineErr.quantity);
        if (lineErr?.unitPrice) messages.push(lineErr.unitPrice);
        if (lineErr?.taxRate) messages.push(lineErr.taxRate);
        if (lineErr?.debitAccountCode) messages.push(lineErr.debitAccountCode);
      });
  }
  return messages;
}

export function validatePurchaseInvoiceForm(
  invoiceDate: string,
  supplierId: string,
  creditAccountCode: string,
  vatAccountCode: string,
  lines: PurchaseInvoiceLineRow[],
): PurchaseInvoiceFieldErrors {
  const nextErrors: PurchaseInvoiceFieldErrors = {};
  if (!invoiceDate) nextErrors.invoiceDate = 'Ngày hóa đơn là bắt buộc';
  if (!supplierId) nextErrors.supplierId = 'Nhà cung cấp là bắt buộc';
  if (!creditAccountCode?.trim()) nextErrors.creditAccountCode = 'TK Có (công nợ) là bắt buộc';
  if (!vatAccountCode?.trim()) nextErrors.vatAccountCode = 'TK thuế GTGT là bắt buộc';
  lines.forEach((l, i) => {
    const lineErr: PurchaseInvoiceLineFieldErrors = {};
    if (!l.materialCode) lineErr.materialCode = `Dòng ${i + 1}: chưa nhập mã vật tư`;
    if (!(Number(l.quantity) > 0)) lineErr.quantity = `Dòng ${i + 1}: số lượng phải > 0`;
    if (!(Number(l.unitPrice) >= 0)) lineErr.unitPrice = `Dòng ${i + 1}: đơn giá không hợp lệ`;
    if (!(Number(l.taxRate) >= 0)) lineErr.taxRate = `Dòng ${i + 1}: thuế suất không hợp lệ`;
    if (!l.debitAccountCode?.trim()) lineErr.debitAccountCode = `Dòng ${i + 1}: chưa nhập TK Nợ`;
    if (Object.keys(lineErr).length > 0) {
      nextErrors.lines = nextErrors.lines ?? {};
      nextErrors.lines[i] = lineErr;
    }
  });
  return nextErrors;
}
